const email = $input.first().json;
const from = email.from?.text || email.from || '';
const to = email.to?.text || email.to || '';
const subject = email.subject || '';
const body = (email.text || email.body || '').substring(0, 5000);
const date = email.date || email.created || new Date().toISOString();

// Extract potential client names from From/To/Subject
const extractNames = (text) => {
  if (!text) return [];
  // Get display names and email local parts
  const names = [];
  const displayNames = text.match(/"([^"]+)"/g) || [];
  displayNames.forEach(n => names.push(n.replace(/"/g, '')));
  const emails = text.match(/<([^>]+)>/g) || [];
  emails.forEach(e => {
    const local = e.replace(/[<>]/g, '').split('@')[0];
    if (local && !names.some(n => n.toLowerCase() === local.toLowerCase())) {
      names.push(local);
    }
  });
  return names;
};

const potentialClients = [
  ...extractNames(from),
  ...extractNames(to),
];

// Clean up subject for matching
const cleanSubject = subject.replace(/^(re:|fw:|fwd:)/i, '').trim();

return [{
  json: {
    from,
    to,
    subject,
    cleanSubject,
    body,
    date,
    potentialClients: [...new Set(potentialClients)]
  }
}];

const emailData = $('Parse Email Content').first().json;
const clientsData = $('Fetch Known Clients').first().json;

const knownClients = clientsData.clients || [];
const potentialClients = emailData.potentialClients || [];
const cleanSubject = emailData.cleanSubject || '';
const from = emailData.from || '';
const to = emailData.to || '';
const allText = `${from} ${to} ${cleanSubject}`.toLowerCase();

// Match against known clients (fuzzy)
const matchedClients = knownClients.filter(client => {
  const clientLower = client.toLowerCase();
  // Direct match in any field
  if (allText.includes(clientLower)) return true;
  // Match potential names
  if (potentialClients.some(p => p.toLowerCase().includes(clientLower))) return true;
  // Match last name (e.g. 'PT MAPID' matches 'MAPID')
  const words = clientLower.split(/\s+/);
  if (words.length > 1 && words.some(w => w.length > 3 && allText.includes(w))) return true;
  return false;
});

if (matchedClients.length === 0) {
  // No match found - try to create entry with subject as identifier
  return [{
    json: {
      ...emailData,
      matchedClients: [],
      noMatch: true
    }
  }];
}

return [{
  json: {
    ...emailData,
    matchedClients,
    noMatch: false
  }
}];

const emailData = $('Match to Known Clients').first().json;
const matchedClients = emailData.matchedClients || [];

// Create one entry per matched client
return matchedClients.map(client => ({
  json: {
    client_name: client,
    from: emailData.from,
    to: emailData.to,
    subject: emailData.subject,
    body: emailData.body,
    date: emailData.date
  }
}));

